SELECT file_type, AVG(file_size) AS average_file_size
FROM sequence_files
GROUP BY file_type;

SELECT motif_id, COUNT(occurrence_id) AS occurrence_count
FROM motif_occurrences
GROUP BY motif_id;

SELECT COUNT(*)
FROM motif_occurrences
WHERE p_value < 0.05;

SELECT annotation_type
FROM annotations
WHERE confidence_score = (SELECT MAX(confidence_score) FROM annotations);

SELECT COUNT(*) 
FROM motifs 
WHERE public_domain = 1;

SELECT COUNT(DISTINCT motif_id)
FROM motif_annotations
WHERE confidence_score > 0.8;

SELECT TRIM(orientation) AS trimmed_orientation, p_value
FROM motif_occurrences
WHERE p_value < 0.05;

SELECT file_path
FROM sequence_files
WHERE sequence_id = 1;

SELECT COUNT(occurrence_id) AS occurrence_count, MAX(score) AS max_score
FROM motif_occurrences
WHERE motif_id = 1;
